SELECT SUM(total_spent) AS total_amount
FROM customers
WHERE last_purchase_date >= DATE('now', '-30 days');

SELECT AVG(DISTINCT total_spent) AS average_total_spent
FROM customers
WHERE country = 'US';

SELECT product_name
FROM products
WHERE stock_quantity = (
  SELECT MAX(stock_quantity) FROM products
)
ORDER BY product_name;

SELECT product_id, product_name
FROM products
WHERE stock_quantity = 0;

SELECT SUM(ps.available_stock) AS total_quantity_out_of_stock
FROM product_sizes ps
WHERE ps.available_stock = 0;
